#include <bits/stdc++.h>
using namespace std;
typedef unsigned long long ll;
struct ball{
	int l,r,len;
	ll sum;
}a[3000000];
int top;
int main(){
	int n;
	cin>>n;
	for(int i=0;i<n;i++){
		int op;
		cin>>op;
		if(op==1){
			int l,r;
			cin>>l>>r;
			a[++top].l=l;
			a[top].r=r;
			a[top].len=r-l+1;
			a[top].sum=(ll)(l+r)*a[top].len/2;
		}else{
			ll k,ans=0;
			cin>>k;
			while(k){
				if(k>=a[top].len){
					ans+=a[top].sum;
					k-=a[top--].len;
				}else{
					ans+=(a[top].r-k+1+a[top].r)*k/2;
					a[top].r-=k;
					a[top].len-=k;
					a[top].sum=(ll)(a[top].l+a[top].r)*a[top].len/2;
					k=0;
				}
			}
			cout<<ans<<endl;
		}
	}
	return 0;
}
